#ifndef API10PUBLISHER_FSM_H_
#define API10PUBLISHER_FSM_H_

//===================================================================================================================
//  API 10 Publisher State Machine declarations.
//===================================================================================================================
/* API10Publisher state machine states */
typedef enum
{
    STATE_API10PUBLISHER_NONE,
    STATE_API10PUBLISHER_INACTIVE, // PlantUML diagram state Inactive
    STATE_API10PUBLISHER_ACTIVE, // PlantUML diagram state Active
    STATE_API10PUBLISHER_PUBLISHING, // PlantUML diagram state Publishing
    NUM_OF_API10PUBLISHER_STATES
} API10PUBLISHER_STATE_TYPE;

/* declaration of the structure that will be passed as a function argument to the state machine auto generated functions */
typedef struct
{
    API10PUBLISHER_STATE_TYPE State;    /* the current state of the state machine */
    BOOL_TYPE Transition;   /* TRUE event triggered a state transition else FALSE */
} API10PUBLISHER_FSM_VAR_TYPE;

/* API 10 Publisher State Machine state machine events */
typedef enum
{
    EVENT_DISABLE_PUBLISHING, // PlantUML diagram event Disable_Publishing
    EVENT_ENABLE_PUBLISHING, // PlantUML diagram event Enable_Publishing
    EVENT_START_PUBLISHING, // PlantUML diagram event Start_Publishing
    EVENT_STOP_PUBLISHING // PlantUML diagram event Stop_Publishing
} API10PUBLISHER_EVENT_TYPE;

/* API 10 Publisher State Machine state machine control functions */
static void API10PublisherInitialize(API10PUBLISHER_STATE_TYPE * state);
static void API10PublisherExecute(API10PUBLISHER_STATE_TYPE * state);
static void API10PublisherEvent(API10PUBLISHER_EVENT_TYPE event, API10PUBLISHER_FSM_VAR_TYPE * fsm_var);
static API10PUBLISHER_FSM_VAR_TYPE API10PublisherBuildFsmVar(API10PUBLISHER_STATE_TYPE state);

/* API 10 Publisher State Machine state machine customization function prototypes */
static void CheckDataDue(API10PUBLISHER_FSM_VAR_TYPE * fsm_var);
static void CheckMetadataDue(API10PUBLISHER_FSM_VAR_TYPE * fsm_var);
static void PublishNextPacket(API10PUBLISHER_FSM_VAR_TYPE * fsm_var);
static void ResetPublisher(API10PUBLISHER_FSM_VAR_TYPE * fsm_var);
static void UpdateTimer(API10PUBLISHER_FSM_VAR_TYPE * fsm_var);

//===================================================================================================================
//  API 10 Publisher State Machine definitions.
//===================================================================================================================
/**
 * @brief Configures the API10Publisher state machine to start execution from the Pseudo Initial state.
 *
 * @param state     pointer to the state machine state variable
 */
static void API10PublisherInitialize(API10PUBLISHER_STATE_TYPE * state)
{
    API10PUBLISHER_FSM_VAR_TYPE fsm_var = API10PublisherBuildFsmVar(STATE_API10PUBLISHER_INACTIVE);
    ResetPublisher(&fsm_var);
    *state = fsm_var.State;
}

/**
 * @brief Executes the API10Publisher state machine do actions.
 *
 * @param state     pointer to the state machine state variable
 */
static void API10PublisherExecute(API10PUBLISHER_STATE_TYPE * state)
{
    API10PUBLISHER_FSM_VAR_TYPE fsm_var = API10PublisherBuildFsmVar(*state);
    switch ( fsm_var.State )
    {
        default:
            // do nothing
            break;
        case STATE_API10PUBLISHER_INACTIVE: // PlantUML diagram state Inactive
            CheckMetadataDue(&fsm_var);
            break;
        case STATE_API10PUBLISHER_ACTIVE: // PlantUML diagram state Active
            UpdateTimer(&fsm_var);
            if ( fsm_var.Transition == FALSE )
            {
                CheckDataDue(&fsm_var);
            }
            break;
        case STATE_API10PUBLISHER_PUBLISHING: // PlantUML diagram state Publishing
            UpdateTimer(&fsm_var);
            if ( fsm_var.Transition == FALSE )
            {
                PublishNextPacket(&fsm_var);
            }
            break;
    }
    *state = fsm_var.State;
}

/**
 * @brief Dispatch the event to the API10Publisher state machine and consume it.
 *
 * @param event     the event to dispatch to the state machine
 * @param state     pointer to the state machine state variable
 */
static void API10PublisherEvent(API10PUBLISHER_EVENT_TYPE event, API10PUBLISHER_FSM_VAR_TYPE * fsm_var)
{
    fsm_var->Transition = FALSE;
    switch ( event )
    {
        default:
            // do nothing
            break;
        case EVENT_DISABLE_PUBLISHING: // PlantUML diagram event Disable_Publishing
            switch ( fsm_var->State )
            {
                default:
                    // do nothing
                    break;
                case STATE_API10PUBLISHER_ACTIVE: // PlantUML diagram state Active
                    /* go to state Inactive */
                    fsm_var->State = STATE_API10PUBLISHER_INACTIVE;
                    ResetPublisher(fsm_var);
                    fsm_var->Transition = TRUE;
                    break;
                case STATE_API10PUBLISHER_PUBLISHING: // PlantUML diagram state Publishing
                    /* go to state Inactive */
                    fsm_var->State = STATE_API10PUBLISHER_INACTIVE;
                    ResetPublisher(fsm_var);
                    fsm_var->Transition = TRUE;
                    break;
            }
            break;
        case EVENT_ENABLE_PUBLISHING: // PlantUML diagram event Enable_Publishing
            switch ( fsm_var->State )
            {
                default:
                    // do nothing
                    break;
                case STATE_API10PUBLISHER_INACTIVE: // PlantUML diagram state Inactive
                    /* go to state Active */
                    fsm_var->State = STATE_API10PUBLISHER_ACTIVE;
                    fsm_var->Transition = TRUE;
                    break;
            }
            break;
        case EVENT_START_PUBLISHING: // PlantUML diagram event Start_Publishing
            switch ( fsm_var->State )
            {
                default:
                    // do nothing
                    break;
                case STATE_API10PUBLISHER_ACTIVE: // PlantUML diagram state Active
                    /* go to state Publishing */
                    fsm_var->State = STATE_API10PUBLISHER_PUBLISHING;
                    PublishNextPacket(fsm_var);
                    fsm_var->Transition = TRUE;
                    break;
            }
            break;
        case EVENT_STOP_PUBLISHING: // PlantUML diagram event Stop_Publishing
            switch ( fsm_var->State )
            {
                default:
                    // do nothing
                    break;
                case STATE_API10PUBLISHER_PUBLISHING: // PlantUML diagram state Publishing
                    /* go to state Active */
                    fsm_var->State = STATE_API10PUBLISHER_ACTIVE;
                    fsm_var->Transition = TRUE;
                    break;
            }
            break;
    }
}

/**
 * @brief Define the API10PUBLISHER_FSM_VAR_TYPE with the passed state argument
 * @param state = the current state of the state machine
 * @return = the API10PUBLISHER_FSM_VAR_TYPE initialized with the state argument
 */
static API10PUBLISHER_FSM_VAR_TYPE API10PublisherBuildFsmVar(API10PUBLISHER_STATE_TYPE state)
{
    API10PUBLISHER_FSM_VAR_TYPE fsm_var;
    fsm_var.State = state;
    fsm_var.Transition = FALSE;
    return ( fsm_var );
}



#endif /* API10PUBLISHER_FSM_H_ */
